export const GetListDetailsDocument = `
    query GetListDetails($globalWhere: triples_bool_exp, $tagPredicateId: String, $limit: Int, $offset: Int, $orderBy: [triples_order_by!]) {
  globalTriplesAggregate: triples_aggregate(where: $globalWhere) {
    aggregate {
      count
    }
  }
  globalTriples: triples(
    where: $globalWhere
    limit: $limit
    offset: $offset
    order_by: $orderBy
  ) {
    term_id
    counter_term_id
    subject {
      term_id
      label
      wallet_id
      image
      type
      term {
        vaults {
          position_count
        }
      }
      tags: as_subject_triples_aggregate(
        where: {predicate_id: {_eq: $tagPredicateId}}
      ) {
        nodes {
          object {
            label
            term_id
            taggedIdentities: as_object_triples_aggregate {
              nodes {
                subject {
                  label
                  term_id
                }
                term_id
              }
              aggregate {
                count
              }
            }
          }
        }
        aggregate {
          count
        }
      }
    }
    object {
      term_id
      label
      wallet_id
      image
      type
    }
    predicate {
      term_id
      label
      wallet_id
      image
      type
    }
    term {
      vaults(where: {curve_id: {_eq: "1"}}) {
        current_share_price
        position_count
        total_shares
      }
    }
    counter_term {
      vaults(where: {curve_id: {_eq: "1"}}) {
        current_share_price
        position_count
        total_shares
      }
    }
  }
}
    `;

